proof_block:
// Enable the vstd array axioms (in particular the `=~=`-to-pointwise
// equivalence on `[A; N]`), so the prover can attempt array
// extensional equality without manual deref of the axiom.
broadcast use vstd::array::group_array_axioms;

// The synthetic det fn has an `==>`-shaped postcondition, so the
// per-state ensures conjuncts are NOT free hypotheses at the top of the
// body.  Re-introduce them by wrapping the proof in
// `if (full_antecedent) { ... }`: inside the `then` branch every
// conjunct is a hypothesis, and outside it the implication is vacuous.
if ({
    &&& (post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
    &&& (post1_self_.wf())
    &&& (post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
    &&& (post2_self_.wf())
}) {
    // Collapse the two `=~=` ensures (both run against the same witness
    // `pre_self_.seq@.update(i as int, out)`) into a single Seq /
    // Ghost<Seq> / view equality on the two post states.  Done in a
    // helper lemma so the chained `=~=`-to-`==` lifts are localised.
    lemma_array_set_seq_uniq(pre_self_, i, out, post1_self_, post2_self_);

    // Surface the lemma's conclusions in the prover's context.
    assert(post1_self_.seq@ == post2_self_.seq@);
    assert(post1_self_.seq == post2_self_.seq);
    assert(post1_self_@ == post2_self_@);

    // Pointwise on the post states' view: both equal the same update of
    // pre's view, so they agree at every index.  We assert this with a
    // case-split on whether `j == i` so the `Seq::update` axiom fires
    // on the second-disjunct (== out) and on the first-disjunct
    // (== pre.seq@[j]) for each j.
    assert forall|j: int| 0 <= j < post1_self_.seq@.len()
        implies post1_self_.seq@[j] == post2_self_.seq@[j] by {
        assert(post1_self_.seq@[j] == pre_self_.seq@.update(i as int, out)[j]);
        assert(post2_self_.seq@[j] == pre_self_.seq@.update(i as int, out)[j]);
        if j == i as int {
            assert(post1_self_.seq@[j] == out);
            assert(post2_self_.seq@[j] == out);
        } else {
            assert(post1_self_.seq@[j] == pre_self_.seq@[j]);
            assert(post2_self_.seq@[j] == pre_self_.seq@[j]);
        }
    }

    // Sequence extensionality lifts pointwise equality to full `==`.
    assert(post1_self_.seq@ =~= post2_self_.seq@);
    assert(post1_self_.seq@ == post2_self_.seq@);

    // r1, r2 are both unit, so they are trivially equal.
    assert(r1 == r2);
}

helper_lemmas:
proof fn lemma_array_set_seq_uniq<A, const N: usize>(
    pre_self_: Array<A, N>, i: usize, out: A,
    post1_self_: Array<A, N>, post2_self_: Array<A, N>,
)
    requires
        post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out),
        post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out),
    ensures
        post1_self_.seq@ == post2_self_.seq@,
        post1_self_.seq == post2_self_.seq,
        post1_self_@ == post2_self_@,
{
    assert(post1_self_.seq@ == pre_self_.seq@.update(i as int, out));
    assert(post2_self_.seq@ == pre_self_.seq@.update(i as int, out));
    assert(post1_self_.seq@ =~= post2_self_.seq@);
    assert(post1_self_.seq@ == post2_self_.seq@);
    assert(post1_self_.seq =~= post2_self_.seq);
    assert(post1_self_.seq == post2_self_.seq);
    assert(post1_self_@ =~= post2_self_@);
    assert(post1_self_@ == post2_self_@);
}
